+class WakeupClosure: public ThreadClosure {
+  void do_thread(Thread* thread) {
+    JavaThread *jt = JavaThread::cast(thread);
+    jt->wakeup_sleep();
+    jt->parker()->unpark();
+    jt->_ParkEvent->unpark();
+  }
+};
